import express from 'express';
import path from 'path';
import cookieParser from 'cookie-parser';
import { google } from 'googleapis';
import { createServer as createViteServer } from 'vite';
import { Readable } from 'stream';
import fs from 'fs';

const app = express();
const PORT = 3000;

const DATA_DIR = path.join(process.cwd(), 'data');
const DB_FILE = path.join(DATA_DIR, 'db.json');

// Ensure local data folder exists inside app directory for USB portability
if (!fs.existsSync(DATA_DIR)) {
  fs.mkdirSync(DATA_DIR, { recursive: true });
}

app.use(express.json({ limit: '50mb' }));
app.use(express.urlencoded({ extended: true, limit: '50mb' }));
app.use(cookieParser());

// Helper to get OAuth2 client dynamically using request host
function getOAuth2Client(req: express.Request) {
  const clientId = process.env.CLIENT_ID || process.env.GOOGLE_CLIENT_ID || '';
  const clientSecret = process.env.CLIENT_SECRET || process.env.GOOGLE_CLIENT_SECRET || '';

  const protocol = req.headers['x-forwarded-proto'] || req.protocol || 'https';
  const host = req.headers['x-forwarded-host'] || req.headers.host || 'localhost:3000';
  const redirectUri = `${protocol}://${host}/api/auth/google/callback`;

  return new google.auth.OAuth2(clientId, clientSecret, redirectUri);
}

// 1. Health check
app.get('/api/health', (_req, res) => {
  res.json({ status: 'ok', time: new Date().toISOString() });
});

// 2. Get Google Auth URL
app.get('/api/auth/google/url', (req, res) => {
  try {
    const clientId = process.env.CLIENT_ID || process.env.GOOGLE_CLIENT_ID || '';
    if (!clientId) {
      return res.status(400).json({
        url: null,
        error: 'Las credenciales de Google Drive (CLIENT_ID) aún no han sido configuradas. Puede utilizar la Nube Integrada de 1-Clic sin credenciales.',
      });
    }
    const oauth2Client = getOAuth2Client(req);
    const authUrl = oauth2Client.generateAuthUrl({
      access_type: 'offline',
      prompt: 'select_account consent',
      scope: [
        'https://www.googleapis.com/auth/drive.file',
        'https://www.googleapis.com/auth/userinfo.email',
        'https://www.googleapis.com/auth/userinfo.profile',
      ],
    });
    res.json({ url: authUrl });
  } catch (err: any) {
    console.error('Error generating Google Auth URL:', err);
    res.status(500).json({ error: err.message || 'Error al configurar la autenticación de Google' });
  }
});

// 3. OAuth Callback handler
app.get('/api/auth/google/callback', async (req, res) => {
  const code = req.query.code as string;
  if (!code) {
    return res.status(400).send('Falta código de autorización de Google.');
  }

  try {
    const oauth2Client = getOAuth2Client(req);
    const { tokens } = await oauth2Client.getToken(code);
    oauth2Client.setCredentials(tokens);

    // Get user info
    let userEmail = 'usuario@gmail.com';
    try {
      const oauth2 = google.oauth2({ version: 'v2', auth: oauth2Client });
      const userInfo = await oauth2.userinfo.get();
      if (userInfo.data.email) {
        userEmail = userInfo.data.email;
      }
    } catch (e) {
      console.warn('Could not fetch Google user info:', e);
    }

    // Store tokens in cookie
    res.cookie('gdrive_tokens', JSON.stringify(tokens), {
      httpOnly: true,
      secure: true,
      sameSite: 'lax',
      maxAge: 30 * 24 * 60 * 60 * 1000, // 30 days
    });

    res.cookie('gdrive_email', userEmail, {
      httpOnly: false,
      secure: true,
      sameSite: 'lax',
      maxAge: 30 * 24 * 60 * 60 * 1000,
    });

    // Close popup and notify opener window
    const htmlResponse = `
      <!DOCTYPE html>
      <html>
        <head><title>Autenticación Exitosa</title></head>
        <body style="font-family: sans-serif; text-align: center; padding: 40px; background: #0f172a; color: white;">
          <h2>¡Conexión con Google Drive Exitosa!</h2>
          <p>Cuenta: <strong>${userEmail}</strong></p>
          <p>Cerrando ventana y regresando al catálogo...</p>
          <script>
            if (window.opener) {
              window.opener.postMessage({
                type: 'GOOGLE_AUTH_SUCCESS',
                email: '${userEmail}'
              }, '*');
            }
            setTimeout(function() { window.close(); }, 1500);
          </script>
        </body>
      </html>
    `;
    res.send(htmlResponse);
  } catch (err: any) {
    console.error('Error exchanging Google auth code:', err);
    res.status(500).send(`Error en autenticación de Google Drive: ${err.message}`);
  }
});

// 4. Check Auth Status
app.get('/api/auth/google/status', (req, res) => {
  const tokensCookie = req.cookies.gdrive_tokens;
  const emailCookie = req.cookies.gdrive_email;

  if (tokensCookie) {
    res.json({ authenticated: true, email: emailCookie || 'google-user@gmail.com' });
  } else {
    res.json({ authenticated: false });
  }
});

// 5. Logout endpoint
app.post('/api/auth/google/logout', (_req, res) => {
  res.clearCookie('gdrive_tokens');
  res.clearCookie('gdrive_email');
  res.json({ success: true });
});

// 6. Upload/Sync PDF to Google Drive
app.post('/api/drive/upload-catalog', async (req, res) => {
  const tokensCookie = req.cookies.gdrive_tokens;
  if (!tokensCookie) {
    return res.status(401).json({
      error: 'No se ha iniciado sesión con Google Drive. Por favor presione "Iniciar Sesión con Google Drive".',
    });
  }

  try {
    const tokens = JSON.parse(tokensCookie);
    const oauth2Client = getOAuth2Client(req);
    oauth2Client.setCredentials(tokens);

    const drive = google.drive({ version: 'v3', auth: oauth2Client });

    const { pdfBase64, filename = 'Catalogo_Oficial_TAZZ.pdf' } = req.body;
    if (!pdfBase64) {
      return res.status(400).json({ error: 'Falta el contenido PDF en formato base64.' });
    }

    // Strip data URL header if present
    const cleanBase64 = pdfBase64.replace(/^data:application\/pdf;base64,/, '');
    const buffer = Buffer.from(cleanBase64, 'base64');
    const stream = Readable.from(buffer);

    // Check if file already exists in Drive to overwrite it (preserving single link)
    const existingSearch = await drive.files.list({
      q: `name = '${filename}' and trashed = false`,
      fields: 'files(id, name, webViewLink, webContentLink)',
    });

    let fileId = '';
    let webViewLink = '';

    if (existingSearch.data.files && existingSearch.data.files.length > 0) {
      // UPDATE existing file content
      fileId = existingSearch.data.files[0].id!;
      console.log(`Actualizando archivo existente en Google Drive. ID: ${fileId}`);

      const updateRes = await drive.files.update({
        fileId: fileId,
        media: {
          mimeType: 'application/pdf',
          body: stream,
        },
        fields: 'id, name, webViewLink, webContentLink',
      });

      fileId = updateRes.data.id!;
      webViewLink = updateRes.data.webViewLink || `https://drive.google.com/file/d/${fileId}/view`;
    } else {
      // CREATE new file in Drive
      console.log('Creando nuevo archivo de catálogo en Google Drive...');
      const createRes = await drive.files.create({
        requestBody: {
          name: filename,
          mimeType: 'application/pdf',
          description: 'Catálogo Oficial de Productos - TAZZ SHOPPER PRO',
        },
        media: {
          mimeType: 'application/pdf',
          body: stream,
        },
        fields: 'id, name, webViewLink, webContentLink',
      });

      fileId = createRes.data.id!;
      webViewLink = createRes.data.webViewLink || `https://drive.google.com/file/d/${fileId}/view`;

      // Set permission to anyone with link can view
      await drive.permissions.create({
        fileId: fileId,
        requestBody: {
          role: 'reader',
          type: 'anyone',
        },
      });
    }

    // Direct embed link or view link
    const viewUrl = webViewLink || `https://drive.google.com/file/d/${fileId}/view`;

    res.json({
      success: true,
      fileId,
      url: viewUrl,
      updatedAt: new Date().toLocaleString('es-PE'),
      message: '¡Catálogo sincronizado exitosamente en Google Drive! El enlace se mantiene constante para todos sus clientes.',
    });
  } catch (err: any) {
    console.error('Error uploading to Google Drive:', err);
    res.status(500).json({
      error: `Error al subir PDF a Google Drive: ${err.message || err}`,
    });
  }
});

// Start Vite middleware in dev, or serve dist in production
async function startServer() {
  if (process.env.NODE_ENV !== 'production') {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: 'spa',
    });
    app.use(vite.middlewares);
  } else {
    const possibleDistPaths = [
      path.join(__dirname, 'dist'),
      path.join(__dirname, '..', 'dist'),
      path.join(process.cwd(), 'dist'),
    ];
    if ((process as any).resourcesPath) {
      possibleDistPaths.unshift(path.join((process as any).resourcesPath, 'app.asar', 'dist'));
      possibleDistPaths.unshift(path.join((process as any).resourcesPath, 'app', 'dist'));
    }
    const fs = await import('fs');
    const distPath = possibleDistPaths.find((p) => fs.existsSync(p)) || possibleDistPaths[0];
    console.log(`[Express] Serviendo interfaz desde: ${distPath}`);

    app.use(express.static(distPath));
    app.get('*', (_req, res) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, '0.0.0.0', () => {
    console.log(`Servidor iniciado en http://0.0.0.0:${PORT}`);
  });
}

startServer();
